proxyConfig.advanced_config:
__authelia_forward_auth__
# Subsonic API endpoints bypass Authelia — mobile clients (Symfonium,
# play:Sub, DSub, etc.) send their own Basic auth or u/p/t Subsonic
# credentials and don't speak OIDC / forward-auth.
location /rest/ {
  proxy_pass $forward_scheme://$server:$port;
  proxy_set_header Host $host;
  proxy_set_header X-Real-IP $remote_addr;
  proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
  proxy_set_header X-Forwarded-Proto $scheme;
  auth_request off;
}
location /share/ {
  # Public share links — never gated.
  proxy_pass $forward_scheme://$server:$port;
  proxy_set_header Host $host;
  auth_request off;
}
